#include <bits/stdc++.h>
using namespace std;
int main(){
    int d,n,x[21],y[21],k[21];
    long long ans=0,sum=0;
    cin>>d>>n;
    for(int i=1;i<=n;i++)cin>>x[i]>>y[i]>>k[i];
    for(int i=0;i<=128;i++){
        for(int j=0;j<=128;j++){
            int tmp=0;
            for(int z=1;z<=n;z++){
                if(x[z]>=i-d && x[z]<=i+d && y[z]>=j-d && y[z]<=j+d)tmp+=k[z];
            }
            if(tmp>ans)ans=tmp,sum=1;
            else if(tmp==ans)sum++;
        }
    }
    cout<<sum<<' '<<ans;
    return 0;
}
